function parseFormat(args) {
  const idx = args.indexOf('--format');
  if (idx === -1 || !args[idx + 1]) {
    throw new AppError('usage: export-<entity> --format <json|csv>', 2);
  }
  return args[idx + 1];
}

function toCSV(rows) {
  if (rows.length === 0) return '';
  const keys = Object.keys(rows[0]);
  const lines = rows.map((r) => keys.map((k) => r[k]).join(','));
  return [keys.join(','), ...lines].join('\n') + '\n';
}

function writeExport(entity, rows, format) {
  if (format !== 'json' && format !== 'csv') {
    throw new AppError(`unsupported format: ${format}`, 2);
  }
  const content = format === 'csv' ? toCSV(rows) : JSON.stringify(rows, null, 2) + '\n';
  const filepath = path.join(outputDir, `${entity}.${format}`);
  fs.mkdirSync(outputDir, { recursive: true });
  fs.writeFileSync(filepath, content);
  return filepath;
}

